  "verses": [
    {
      "n": 1,
      "column": "left",
      "text": "Eena Pamahzifchana\nGetava/ ta Eſraktera.\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Es dseedaschu no\nta KUNGA Schehlaſtibahm\nmuhschigi/ un darriſchn winna\nBateetibu finnamu ar mann\nMutti/ lihds Raddn Raddeen.\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Jo es ſaknu/ ka weena\nmuhschiga Schehlaſtiba taps us-\nzelta/ tu turreſi tavu Bateetibu\npaſtahwigi Debbeﬁs.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Es eſmu Derribu darrijs\nar mannun Jswehleto/ es eſmu\nDahwidam mannam Kalpam\nfwehrejs.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Es apſtiprinaſchu tavu\nDſimmumu muhschigi/ un us-\ntaiſischu tavu Gohda-Krehſlu\nlihds Behrnu Behrneem/ Sela.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Par to flawe tahs Debbe-\nfis ak KUNGS! tavus Brih-\nnumus/ un tavu Pateefibn\neekſch to Swehtu Draudsibas.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Jo ko warrehs eekſch Pa-\ndebbefim tam KUNGA M lihdsu\nturrecht? kurſch buhtu ka tas\nKUNGS ſtarp teem Deewu\nBehrneem?\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Tas STIPRAJS\nDEEWS irr tohti bibjaſains\neekſch to Swehtu Draudsibas/\nun iſbibjaſains pahr wiſſeem/\nkas apkahrt winan irr.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "KUNGS Deews Zebäits/\nkas irr lihds ka tu? tahds ſtip-\nrajs/ ak KUNGS! un tawa\nPateefiba irr apkahrt terwi.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Tu waldi pahr to lepnu\nJuhen/ kad winnas Wilni zet-\nfahe/ tad tu tohs kluffina.\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Tu fatreezi Rakabu ka\nweenu Nokautu/ tu iſkaſi ta-\nwus Eenaidneekus ar tavu ſip-\nru Elkou.\n"
    },
    {
      "n": 12,
      "column": "right",
      "text": "Tew peederr Debbes/ ir\nta Semme tew peederr/ to\nSemmes Wirſu un winnas\nBaggaſibueſi tu dibbinajs.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "To Secineli un Deenas-\nWiddu eſi tu radrijs/ Tahbors\nun Ermons gawile eekſch tawa\nWahrda.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Tew irr weens ſpehzigs\nElkone/ ſtipra irr tawa Rohka/\nun augſta tawa labba Rohka.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Taifniba un Teefa irr ta-\nwa Gohdibas Krehſla Pamatti/\nSchehlaſtiba un Pateefiba ect\ntawa Preekſcha.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Swehtigi irr tee Landis/\nkas mahk gawileht/ ak KUNGS!\ntee staigahs eekſch tawa Waiga\nGaischuma.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Pahr tavu Wahrdtu tee\npreezafees ikdeenas/ un tap8\ntureht? kurſch buhtu ka tas\nzaur tavu Taifnibu pa-augsti-\nnati.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Jo tu eſi winnu Stipri-\nbas Gohdiba/ un zaur tavu lab-\nbu Prahtu taps muhfu Rags\npa-augstinahte.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Jo muhtu preekſchturra-\nmas Bruunas irr pee ta KUN-\nGA/ un pee ta Israëta Swehta\nier muhfu Kehniaſch.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "To Brihdi tu runnaji\nzaur Parahdifchanu us tawem\nSweh-\n"
    }
  ],
